function solve(value: number[], limit: number[]): number {
    const n = value.length;
    const a: [number, number][] = [];
    for (let i = 0; i < n; i++) {
        a.push([value[i], limit[i]]);
    }
    a.sort((x, y) => {
        if (x[1] !== y[1]) {
            return x[1] - y[1];
        }
        return y[0] - x[0];
    });

    const heap: number[] = [];
    for (const [val, lim] of a) {
        heap.push(val);
        heap.sort((a, b) => a - b);
        if (heap.length > lim) {
            heap.shift();
        }
    }

    return heap.reduce((sum, val) => sum + val, 0);
}
```

