    jobs.sort((a, b) => {
        if (a[1] !== b[1]) {
            return a[1] - b[1];
        }
        return b[0] - a[0];
    });

    const heap = new MinHeap();
    let ans = 0;

    for (const [v, lim] of jobs) {
        if (heap.size() < lim) {
            heap.push(v);
