        if (a.limit !== b.limit) {
            return a.limit - b.limit;
        }
        return b.v - a.v;
    });

    const heap = new MinHeap();
    let ans = 0;
    let ptr = 0;

    for (let active = 1; active <= n; active++) {
        while (ptr < n && items[ptr].limit <= active) {
            if (heap.size() < active) {
                heap.enqueue(items[ptr].v);
                ans += items[ptr].v;
